#include <vector>
#include <algorithm>

using namespace std;

/**
 * @brief Returns the maximum number of fixed points achievable after deleting any number of elements.
 * 
 * @param nums The input integer array.
 * @return int The maximum number of fixed points.
 */
long long solve(std::vector<long long> nums) {
    int n = nums.size();

    // The problem asks for the maximum number of elements that can remain such that 
    // for the remaining sequence, nums'[i] == i for as many indices i as possible.
    // Let the indices we keep from the original array be i_0, i_1, ..., i_{k-1}, 
    // where 0 <= i_0 < i_1 < ... < i_{k-1} < n.
    // The remaining sequence nums' is [nums[i_0], nums[i_1], ..., nums[i_{k-1}]].
    // A fixed point occurs at index j in nums' if nums'[j] == j.
    // This means we need nums[i_j] == j.
    // We want to maximize k such that there exist indices i_0 < i_1 < ... < i_{k-1}
    // where nums[i_j] == j for all j = 0, 1, ..., k-1.

    // This is equivalent to finding the longest subsequence of nums, say (nums[i_0], nums[i_1], ...),
    // such that nums[i_j] = j.

    // We can use a greedy approach or dynamic programming.
    // Since we require nums[i_j] = j, we are looking for the longest increasing subsequence
    // of target values (0, 1, 2, ...) that can be matched by values in nums 
    // at strictly increasing indices.

    int required_value = 0; // The target value for the next fixed point (j in nums'[j] == j)
    int fixed_points_count = 0;

    for (int i = 0; i < n; ++i) {
        // Check if the current element nums[i] can serve as the next fixed point.
        // If nums[i] equals the value we are currently looking for (required_value),
        // we select it to be part of our resulting fixed-point sequence.
        // By selecting it, we advance the required value for the next fixed point.
        if (nums[i] == required_value) {
            fixed_points_count++;
            required_value++;
        }
        // If nums[i] != required_value, we must delete this element because if we keep it,
        // it either won't be a fixed point at the current required index, or it will
        // displace subsequent elements, making it impossible to achieve the current 
        // required_value at the next available index in a way that maximizes the count.
        // Since we are looking for the *longest* subsequence matching (0, 1, 2, ...),
        // we greedily take the earliest occurrence of 'required_value'.
    }

    return fixed_points_count;
}
