class Solution {
public:
    long long solve(std::vector<long long> nums) {
        // This problem can be rephrased as finding the maximum size of a subsequence 
        // where the elements of the subsequence, when mapped to their new indices, 
        // satisfy the fixed-point condition.

        // Let the original array be nums. We select a subsequence S.
        // If S has length k, and S[j] is the j-th element of the subsequence (0-indexed),
        // the condition for a fixed point is S[j] == j.

        // Let the indices of the chosen elements in the original array be i_0, i_1, ..., i_{k-1},
        // where i_0 < i_1 < ... < i_{k-1}.
        // Then S[j] = nums[i_j].
        // The condition becomes: nums[i_j] == j for j = 0, 1, ..., k-1.

        // We want to find the longest sequence i_0 < i_1 < ... < i_{k-1} such that nums[i_j] == j.

        // This is equivalent to finding the Longest Increasing Subsequence (LIS) 
        // on a modified sequence, but a simpler greedy approach works here because the target values (j) 
        // are strictly increasing (0, 1, 2, ...).

        int count = 0; // This will be the current target value j (which is also the current count of fixed points found)

        // We iterate through the original array nums.
        for (int i = 0; i < nums.size(); ++i) {
            // If we choose nums[i] to be the (count)-th element of our subsequence (i.e., S[count]),
            // the condition for it to be a fixed point is nums[i] == count.

            if (nums[i] == count) {
                // We found a suitable element to extend our subsequence and achieve a fixed point.
                // We select this element, and the required next fixed point will be at index 'count + 1'.
                count++;
            }
        }

        // 'count' now holds the maximum number of fixed points achievable.
        return count;
    }
};
